import{o as e,c as i,a}from"./app.7b66a8d7.js";const l='{"title":"CHANGELOG","description":"","frontmatter":{},"headers":[{"level":2,"title":"2022-01-10","slug":"_2022-01-10"},{"level":2,"title":"2021-12-17","slug":"_2021-12-17"},{"level":2,"title":"2021-12-14","slug":"_2021-12-14"},{"level":2,"title":"2021-12-08","slug":"_2021-12-08"}],"relativePath":"changelog.md","lastUpdated":1641762252445}',t={},r=[a('<h1 id="changelog"><a class="header-anchor" href="#changelog" aria-hidden="true">#</a> CHANGELOG</h1><h2 id="_2022-01-10"><a class="header-anchor" href="#_2022-01-10" aria-hidden="true">#</a> 2022-01-10</h2><ul><li>Improved reliability in panel count matrix.</li><li>Fixed a bug in report settings. Some settins were not correctly stored on clone/edit.</li><li>Fixed RFID button in viewer.</li><li>Company Production Overview (beta).</li><li>Full plates selector in plates reports.</li><li>Android first release.</li><li>MOB2: Added support for triangular panels.</li><li>MOB2: Auto-remove duplicate milling operations.</li><li>MOB2: Improved performance and reliability.</li><li>BTL: Improved performance and reliability.</li></ul><h2 id="_2021-12-17"><a class="header-anchor" href="#_2021-12-17" aria-hidden="true">#</a> 2021-12-17</h2><ul><li>ADRIS: Fixed an issue for Ardis csv generation.</li><li>ADRIS: Swith Width and Lenth for Ardis csv export.</li><li>MOB2: Shift feature now based en machine Zeros.</li><li>MOB2: Inside height is count now from the lowest level in frame parts.</li><li>MOB2: Added a new feature for layers generation. Now the user can select between 3 options for generate the layers that corresponds to a certain machine, if the operations coordinates are above machine sizes: <ul><li>Generate anyway: ignore the machine sizes, and generate the operations.</li><li>Do not generate the layer: if any operations is above machine sizes, the layer will not be generated.</li><li>Trim operations up to max size: the operations that exceeds machine sizes, will be trimmed up to the machine limit.</li></ul></li><li>MOB2: Added a new feature for twin nailings patterns. Now the user can select between the regular pattern, or a new one optimized for large panels.</li></ul><h2 id="_2021-12-14"><a class="header-anchor" href="#_2021-12-14" aria-hidden="true">#</a> 2021-12-14</h2><ul><li>Improved operations status indications and disabled actions.</li><li>Solved several bugs in operations (generate_designs, detect_details, prepare_viewer).</li><li>Operation detect_details now has checked boxes by default since most users forget to check it.</li><li>IFC PS clone feature.</li><li>Change Stations menú upgrade.</li><li>mob2+mob1 files: Glueing and bricks bugs fixed.</li></ul><h2 id="_2021-12-08"><a class="header-anchor" href="#_2021-12-08" aria-hidden="true">#</a> 2021-12-08</h2><ul><li>New file versioning in uploads. This solves some updating bugs.</li><li>New file status indicators (see: <a href="https://docs.produuz.it/operations.html#table-of-uploaded-files" target="_blank" rel="noopener noreferrer">https://docs.produuz.it/operations.html#table-of-uploaded-files</a>)</li><li>mob2+mob1 files: Spiral plate nailing for single nailing.</li><li>mob2+mob1 files: Frame nailing matrix fix for proper studs selection.</li></ul>',9)];t.render=function(a,l,t,n,o,s){return e(),i("div",null,r)};export{l as __pageData,t as default};
